import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import './index.css';

interface ErrorBoundaryProps {
  children: React.ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

// Simple Error Boundary to catch render crashes
class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: '2rem', color: '#ef4444', fontFamily: 'sans-serif' }}>
          <h1>Something went wrong.</h1>
          <p>Please check the console for details.</p>
          <pre style={{ background: '#fef2f2', padding: '1rem', borderRadius: '0.5rem', overflow: 'auto' }}>
            {this.state.error?.toString()}
          </pre>
        </div>
      );
    }

    return this.props.children;
  }
}

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <ErrorBoundary>
      <App />
    </ErrorBoundary>
  </React.StrictMode>
);

import { GoogleGenAI, Type } from "@google/genai";

// Lazy initialization to prevent app crash on startup if environment variables aren't ready
let aiClient: GoogleGenAI | null = null;

const getAiClient = () => {
  if (!aiClient) {
    // Robustly retrieve the API key checking multiple locations to support 
    // Vite builds, preview environments, and polyfills.
    let apiKey = '';

    try {
      // Check standard process.env (replaced by Vite define or present in Node)
      apiKey = process.env.API_KEY || '';
    } catch (e) {
      // Ignore ReferenceError if process is not defined
    }

    if (!apiKey && typeof import.meta !== 'undefined') {
       // Check Vite's import.meta.env
       apiKey = import.meta.env?.VITE_API_KEY || '';
    }

    if (!apiKey && typeof window !== 'undefined') {
      // Check global window.process polyfill
      apiKey = (window as any).process?.env?.API_KEY || '';
    }

    // Initialize with provided key or fallback to prevent constructor error
    // The actual API call will fail gracefully if the key is invalid
    aiClient = new GoogleGenAI({ apiKey: apiKey || "" });
  }
  return aiClient;
};

export interface SongConcept {
  title: string;
  genre: string;
  mood: string;
  lyricsSnippet: string;
  instrumentationIdeas: string[];
}

export const generateSongConcept = async (
  vision: string,
  genre: string
): Promise<SongConcept> => {
  try {
    const ai = getAiClient();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Generate a song concept based on the following vision: "${vision}" and genre: "${genre}". 
      Provide a catchy title, a mood description, a short snippet of lyrics (chorus), and some instrumentation ideas.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            genre: { type: Type.STRING },
            mood: { type: Type.STRING },
            lyricsSnippet: { type: Type.STRING },
            instrumentationIdeas: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
            },
          },
          required: ["title", "genre", "mood", "lyricsSnippet", "instrumentationIdeas"],
        },
      },
    });

    const text = response.text;
    if (!text) {
        throw new Error("No response text from Gemini");
    }
    return JSON.parse(text) as SongConcept;
  } catch (error) {
    console.error("Error generating song concept:", error);
    throw error;
  }
};

export const editImage = async (base64Data: string, mimeType: string, prompt: string): Promise<string> => {
  try {
    const ai = getAiClient();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: mimeType,
            },
          },
          {
            text: prompt,
          },
        ],
      },
    });

    if (response.candidates && response.candidates[0].content && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return part.inlineData.data;
        }
      }
    }

    throw new Error("No image generated in response");
  } catch (error) {
    console.error("Error editing image:", error);
    throw error;
  }
};

