import { GoogleGenAI, Type } from "@google/genai";

export interface SongConcept {
  title: string;
  genre: string;
  mood: string;
  lyricsSnippet: string;
  instrumentationIdeas: string[];
}

export const generateSongConcept = async (
  vision: string,
  genre: string
): Promise<SongConcept> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate a detailed song concept. 
    User Vision: "${vision}"
    Target Genre: "${genre}"

    The response must be creative, professional, and evocative.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING, description: "Catchy and meaningful song title" },
          genre: { type: Type.STRING, description: "Specific sub-genre description" },
          mood: { type: Type.STRING, description: "Emotional tone of the song" },
          lyricsSnippet: { type: Type.STRING, description: "The most impactful 4-8 lines of the chorus" },
          instrumentationIdeas: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "3-5 specific instrumentation or production ideas"
          },
        },
        required: ["title", "genre", "mood", "lyricsSnippet", "instrumentationIdeas"],
      },
    },
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");
  return JSON.parse(text) as SongConcept;
};

export const editImage = async (base64Data: string, mimeType: string, prompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          inlineData: {
            data: base64Data,
            mimeType: mimeType,
          },
        },
        {
          text: `Please edit this album artwork based on this request: ${prompt}. Maintain the original subject matter but apply the requested stylistic changes.`,
        },
      ],
    },
  });

  // The model might return text along with the image, iterate to find the image part
  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return part.inlineData.data;
    }
  }

  throw new Error("No image was generated in the response");
};

