import React, { useState } from 'react';
import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { HowItWorks } from './components/HowItWorks';
import { Footer } from './components/Footer';
import { SongBuilderModal } from './components/SongBuilderModal';
import { CursorTrace } from './components/CursorTrace';
import { LoginModal } from './components/LoginModal';
import { CheckoutModal } from './components/CheckoutModal';
import { Pricing } from './components/Pricing';
import { TrustedBy } from './components/TrustedBy';
import { SongConcept } from './services/geminiService';

interface OrderItem {
  type: 'concept' | 'release';
  price: number;
  concept?: SongConcept;
}

function App() {
  const [isBuilderOpen, setIsBuilderOpen] = useState(false);
  const [isLoginOpen, setIsLoginOpen] = useState(false);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);

  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [selectedGenre, setSelectedGenre] = useState<string>('');
  const [selectedTier, setSelectedTier] = useState<'standard' | 'premium'>('standard');
  const [orderItem, setOrderItem] = useState<OrderItem | null>(null);

  const handleStartBuilder = (genre?: string, tier: 'standard' | 'premium' = 'standard') => {
    setSelectedGenre(genre || '');
    setSelectedTier(tier);
    setIsBuilderOpen(true);
  };

  const handleOrderSong = (concept: SongConcept) => {
    setIsBuilderOpen(false);
    const price = selectedTier === 'premium' ? 99 : 49;
    setOrderItem({ 
      type: selectedTier === 'premium' ? 'release' : 'concept', 
      price, 
      concept 
    });
    setIsCheckoutOpen(true);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans relative bg-slate-950 text-white selection:bg-indigo-500 selection:text-white">
      <CursorTrace />
      <Navbar 
        onLoginClick={() => setIsLoginOpen(true)}
        isLoggedIn={isLoggedIn}
      />

      <main className="flex-grow">
        <div id="home">
          <Hero onStartBuilder={() => handleStartBuilder(undefined, 'standard')} />
        </div>

        <TrustedBy />

        <div id="how-it-works">
          <HowItWorks />
        </div>

        <Pricing onSelectPlan={(tier) => handleStartBuilder(undefined, tier)} />
      </main>

      <Footer />

      <SongBuilderModal 
        isOpen={isBuilderOpen} 
        onClose={() => setIsBuilderOpen(false)} 
        initialGenre={selectedGenre}
        selectedTier={selectedTier}
        onOrder={handleOrderSong}
      />

      <LoginModal 
        isOpen={isLoginOpen}
        onClose={() => setIsLoginOpen(false)}
        onLogin={() => setIsLoggedIn(true)}
      />

      <CheckoutModal
        isOpen={isCheckoutOpen}
        onClose={() => setIsCheckoutOpen(false)}
        item={orderItem}
      />
    </div>
  );
}

export default App;

import { GoogleGenAI, Type } from "@google/genai";

export interface SongConcept {
  title: string;
  genre: string;
  mood: string;
  lyricsSnippet: string;
  instrumentationIdeas: string[];
}

export const generateSongConcept = async (
  vision: string,
  genre: string
): Promise<SongConcept> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Stwórz koncepcję piosenki. Wizja: "${vision}", Gatunek: "${genre}". 
    Odpowiedz WYŁĄCZNIE w formacie JSON z polami: title, genre, mood, lyricsSnippet (refren), instrumentationIdeas (lista 3-5 pomysłów).`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          genre: { type: Type.STRING },
          mood: { type: Type.STRING },
          lyricsSnippet: { type: Type.STRING },
          instrumentationIdeas: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          },
        },
        required: ["title", "genre", "mood", "lyricsSnippet", "instrumentationIdeas"],
      },
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI nie zwróciło odpowiedzi.");
  return JSON.parse(text) as SongConcept;
};

export const editImage = async (base64Data: string, mimeType: string, prompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt },
      ],
    },
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return part.inlineData.data;
  }
  throw new Error("Nie wygenerowano obrazu.");
};

